// Omnichannel Extractor (v2 — with current_semester)
let source, studentId, message, chatId, careerGoal, currentSemester;
const rawData = $input.first().json;
if (rawData.message && rawData.message.chat) {
    // TELEGRAM SOURCE
    source = 'telegram'; chatId = String(rawData.message.chat.id);
    const text = rawData.message.text || '';
    const parts = text.trim().split(/\s+/);
    message = parts[0] || ''; studentId = parts[1] || '';
    // Parse semester: /recommend <ID> <semester> <career goal...>
    const semPart = parseInt(parts[2]);
    if (!isNaN(semPart) && semPart >= 1 && semPart <= 10) {
        currentSemester = semPart;
        careerGoal = parts.slice(3).join(' ') || '';
    } else {
        currentSemester = null;
        careerGoal = parts.slice(2).join(' ') || '';
    }
} else {
    // WEB SOURCE
    source = 'web'; chatId = null;
    const body = rawData.body || rawData;
    message = body.message || ''; studentId = body.student_id || ''; careerGoal = body.career_goal || '';
    currentSemester = (body.current_semester && body.current_semester >= 1 && body.current_semester <= 10) ? parseInt(body.current_semester) : null;
}
if (message.startsWith('/recommend') && (!studentId || studentId.length < 5)) {
    return [{ json: { source, chatId, error: true, error_message: 'Invalid format. Usage: /recommend <StudentID> <Semester> <CareerGoal>' }}];
}
return [{ json: { source, chatId, student_id: studentId, message, career_goal: careerGoal, current_semester: currentSemester, error: false } }];

const item = $input.first().json;
let hasValidCourses = false;
if (item && item.student_id && item.recommended_courses) {
    const rc = item.recommended_courses;
    if (Array.isArray(rc.courses)) { hasValidCourses = rc.courses.length > 0; }
    else if (Array.isArray(rc)) { hasValidCourses = rc.length > 0; }
}
if (hasValidCourses) {
    return [{ json: { cache_hit: true, ...item } }];
} else {
    return [{ json: { cache_hit: false, student_id: $('Omnichannel Extractor').first().json.student_id } }];
}

const cached = $input.first().json;
let fullResponse = cached.full_response;
if (typeof fullResponse === 'string') { try { fullResponse = JSON.parse(fullResponse); } catch(e) {} }
return [{ json: fullResponse }];

// Hard Logic Pre-Filter v5
// Paste this body into the n8n Code node named "Hard Logic Pre-Filter".
// Output schema intentionally matches v4 for downstream prompt/parser compatibility.

const inputData = $input.all();
const allDataObjects = [];

for (const item of inputData) {
    if (item.json && Array.isArray(item.json.data)) {
        for (const obj of item.json.data) allDataObjects.push(obj);
    } else if (item.json) {
        allDataObjects.push(item.json);
    }
}

const extractor = $('Omnichannel Extractor').first().json;
const studentId = extractor.student_id;
const careerGoal = extractor.career_goal || '';
const requestedSemester = parseSemester(extractor.current_semester);

const studentRow = allDataObjects.find(obj => obj.student_id && obj.grades);
const prereqRows = allDataObjects.filter(obj => obj.prerequisite_code);
const constraintRows = allDataObjects.filter(obj => obj.constraint_id);
const scheduleRows = allDataObjects.filter(obj => obj.component && obj.day);
const studyPlanRows = allDataObjects.filter(obj => obj.semester_number != null && !obj.component && !obj.group_code);
const electiveGroupRows = allDataObjects.filter(obj => obj.group_code != null);

if (!studentRow) {
    return [{ json: { error: true, error_message: `Student ID "${studentId}" not found.` } }];
}

function norm(value) {
    return value == null ? '' : String(value).trim();
}

function toUpper(value) {
    return norm(value).toUpperCase();
}

function toNumber(value, fallback = 0) {
    const parsed = parseFloat(value);
    return Number.isFinite(parsed) ? parsed : fallback;
}

function parseSemester(value) {
    const parsed = parseInt(value, 10);
    return Number.isInteger(parsed) && parsed >= 1 && parsed <= 10 ? parsed : null;
}

function isElectivePlaceholder(courseCode) {
    return /^E\d+$/i.test(norm(courseCode));
}

function isNonCoursePlaceholder(courseCode) {
    return /^(E|UE)\d+$/i.test(norm(courseCode));
}

const grades = Array.isArray(studentRow.grades) ? studentRow.grades.filter(g => g && g.course_code && g.grade) : [];
const failingGrades = new Set(['F', 'FW']);
const nonPassingGrades = new Set(['F', 'FW', 'W', 'U']);

const passedCourseSet = new Set();
const failedCourseCandidates = new Set();

for (const gradeRow of grades) {
    const courseCode = norm(gradeRow.course_code);
    const grade = toUpper(gradeRow.grade);
    if (!courseCode || !grade) continue;

    if (failingGrades.has(grade)) failedCourseCandidates.add(courseCode);
    if (!nonPassingGrades.has(grade)) passedCourseSet.add(courseCode);
}

const passedCourses = [...passedCourseSet];
const failedCourses = [...failedCourseCandidates].filter(code => !passedCourseSet.has(code));

const prereqGraph = {};
for (const row of prereqRows) {
    const courseCode = norm(row.course_code);
    const prereqCode = norm(row.prerequisite_code);
    const condition = toUpper(row.condition || 'NONE');
    if (!courseCode) continue;

    if (!prereqGraph[courseCode]) {
        prereqGraph[courseCode] = { prerequisites: [], condition };
    }

    if (prereqCode && toUpper(prereqCode) !== 'NONE' && prereqCode !== courseCode) {
        prereqGraph[courseCode].prerequisites.push(prereqCode);
    }

    if (condition !== 'NONE') prereqGraph[courseCode].condition = condition;
}

function checkPrereqs(courseCode) {
    const pr = prereqGraph[courseCode];
    if (!pr || pr.condition === 'NONE' || pr.prerequisites.length === 0) return true;

    if (pr.condition === 'MANDATORY' || pr.condition === 'AND') {
        return pr.prerequisites.every(p => passedCourseSet.has(p));
    }

    if (pr.condition === 'OR') {
        return pr.prerequisites.some(p => passedCourseSet.has(p));
    }

    return false;
}

const constraintsData = {};
for (const c of constraintRows) {
    if (c.constraint_id) constraintsData[c.constraint_id] = c;
}

const gpa = toNumber(studentRow.cumulative_gpa, 0);
let maxCredits = 18;

if (constraintsData.C003 && gpa < toNumber(constraintsData.C003.gpa_max, 1.99) + 0.01) {
    maxCredits = toNumber(constraintsData.C003.value, 12);
} else if (
    constraintsData.C002 &&
    gpa >= toNumber(constraintsData.C002.gpa_min, 2.0) &&
    gpa <= toNumber(constraintsData.C002.gpa_max, 2.15)
) {
    maxCredits = toNumber(constraintsData.C002.value, 14);
} else if (constraintsData.C001) {
    maxCredits = toNumber(constraintsData.C001.value, 18);
}

const studyPlanEntries = [];
const studyPlanMap = {};
const studyPlanCredits = {};
const electivePlanEntries = {};

for (const sp of studyPlanRows) {
    const courseCode = norm(sp.course_code);
    const semesterNumber = parseSemester(sp.semester_number);
    if (!courseCode || !semesterNumber) continue;

    const credits = toNumber(sp.credits, 3);
    const entry = { course_code: courseCode, semester_number: semesterNumber, credits };
    studyPlanEntries.push(entry);
    studyPlanMap[courseCode] = semesterNumber;
    studyPlanCredits[courseCode] = credits;

    if (isElectivePlaceholder(courseCode)) {
        if (!electivePlanEntries[courseCode]) electivePlanEntries[courseCode] = [];
        electivePlanEntries[courseCode].push(entry);
    }
}

studyPlanEntries.sort((a, b) => a.semester_number - b.semester_number || a.course_code.localeCompare(b.course_code));

const electiveGroups = {};
const courseToElectiveGroups = {};

for (const eg of electiveGroupRows) {
    const groupCode = norm(eg.group_code);
    const courseCode = norm(eg.course_code);
    if (!groupCode || !courseCode) continue;

    if (!electiveGroups[groupCode]) electiveGroups[groupCode] = [];
    electiveGroups[groupCode].push({
        course_code: courseCode,
        course_name: norm(eg.course_name),
    });

    if (!courseToElectiveGroups[courseCode]) courseToElectiveGroups[courseCode] = new Set();
    courseToElectiveGroups[courseCode].add(groupCode);
}

function planSemestersForCourse(courseCode) {
    if (studyPlanMap[courseCode]) return [studyPlanMap[courseCode]];

    const groups = courseToElectiveGroups[courseCode] ? [...courseToElectiveGroups[courseCode]] : [];
    const semesters = [];
    for (const group of groups) {
        const planEntries = electivePlanEntries[group] || [];
        for (const entry of planEntries) semesters.push(entry.semester_number);
    }

    return semesters;
}

function inferSemesterFromHistory() {
    let highestMatchedSemester = 0;

    for (const gradeRow of grades) {
        const courseCode = norm(gradeRow.course_code);
        if (!courseCode) continue;

        const semesters = planSemestersForCourse(courseCode);
        for (const semester of semesters) {
            if (semester > highestMatchedSemester) highestMatchedSemester = semester;
        }
    }

    if (highestMatchedSemester === 0) return 1;
    return Math.max(1, Math.min(10, highestMatchedSemester));
}

const effectiveSemester = requestedSemester || inferSemesterFromHistory();

const offeredByCode = {};
for (const row of scheduleRows) {
    const courseCode = norm(row.course_code);
    const programCode = norm(row.program_code);
    if (!courseCode || programCode === 'UNIV') continue;

    if (!offeredByCode[courseCode]) {
        offeredByCode[courseCode] = {
            course_name: norm(row.course_name),
            credits: toNumber(row.credits, 3),
            programs: new Set(),
        };
    }

    if (programCode) offeredByCode[courseCode].programs.add(programCode);
}

const mandatoryCourses = [];
const flexibleCourses = [];
const electiveOptions = {};
const seenCodes = new Set();
const skippedFailedRetakes = [];
const studentProgram = norm(studentRow.program_code);

function isOfferedForStudentProgram(courseCode) {
    return !!offeredByCode[courseCode] && offeredByCode[courseCode].programs.has(studentProgram);
}

function courseNameFor(courseCode, fallbackName = '') {
    return (offeredByCode[courseCode] && offeredByCode[courseCode].course_name) || fallbackName || courseCode;
}

function creditsFor(courseCode, fallbackCredits = 3) {
    return toNumber(studyPlanCredits[courseCode], toNumber(offeredByCode[courseCode] && offeredByCode[courseCode].credits, fallbackCredits));
}

function addCourse(target, courseCode, reason, studyPlanTerm, options = {}) {
    if (seenCodes.has(courseCode)) return false;

    const credits = toNumber(options.credits, creditsFor(courseCode, 3));
    target.push({
        course_code: courseCode,
        course_name: courseNameFor(courseCode, options.course_name),
        credits,
        reason,
        is_cross_program: false,
        study_plan_term: studyPlanTerm || null,
        ...options.extra,
    });

    seenCodes.add(courseCode);
    return true;
}

// P1: Failed retakes. Policy: mandatory only when offered under the student's own program.
for (const failedCourse of failedCourses) {
    if (seenCodes.has(failedCourse)) continue;

    if (!offeredByCode[failedCourse]) {
        skippedFailedRetakes.push({ course_code: failedCourse, reason: 'NOT_OFFERED' });
        continue;
    }

    if (!isOfferedForStudentProgram(failedCourse)) {
        skippedFailedRetakes.push({ course_code: failedCourse, reason: 'NOT_OFFERED_IN_STUDENT_PROGRAM' });
        continue;
    }

    addCourse(
        mandatoryCourses,
        failedCourse,
        'FAILED_RETAKE',
        studyPlanMap[failedCourse] || null,
        { credits: creditsFor(failedCourse, offeredByCode[failedCourse].credits) }
    );
}

// P2: Overdue required core courses from earlier semesters.
for (const entry of studyPlanEntries) {
    const code = entry.course_code;
    if (entry.semester_number >= effectiveSemester) continue;
    if (isNonCoursePlaceholder(code)) continue;
    if (seenCodes.has(code) || passedCourseSet.has(code)) continue;
    if (!isOfferedForStudentProgram(code) || !checkPrereqs(code)) continue;

    addCourse(mandatoryCourses, code, 'OVERDUE_CORE', entry.semester_number, { credits: entry.credits });
}

// P3: Current-semester required core courses.
for (const entry of studyPlanEntries) {
    const code = entry.course_code;
    if (entry.semester_number !== effectiveSemester) continue;
    if (isNonCoursePlaceholder(code)) continue;
    if (seenCodes.has(code) || passedCourseSet.has(code)) continue;
    if (!isOfferedForStudentProgram(code) || !checkPrereqs(code)) continue;

    addCourse(mandatoryCourses, code, 'CURRENT_SEMESTER_CORE', entry.semester_number, { credits: entry.credits });
}

const mandatoryCredits = mandatoryCourses.reduce((sum, course) => sum + toNumber(course.credits, 3), 0);
const remainingBudget = maxCredits - mandatoryCredits;

// P4: Current-semester elective options. Study-plan entries contain group placeholders like E1/E2.
for (const entry of studyPlanEntries) {
    const groupCode = entry.course_code;
    if (entry.semester_number !== effectiveSemester) continue;
    if (!isElectivePlaceholder(groupCode)) continue;

    const options = electiveGroups[groupCode] || [];
    for (const option of options) {
        const code = option.course_code;
        if (seenCodes.has(code) || passedCourseSet.has(code)) continue;
        if (!isOfferedForStudentProgram(code) || !checkPrereqs(code)) continue;

        if (!electiveOptions[groupCode]) electiveOptions[groupCode] = [];
        electiveOptions[groupCode].push({
            course_code: code,
            course_name: courseNameFor(code, option.course_name),
            credits: entry.credits,
            elective_group: groupCode,
            reason: 'ELECTIVE_OPTION',
            study_plan_term: entry.semester_number,
        });
    }
}

// P5: Future required core courses.
for (const entry of studyPlanEntries) {
    const code = entry.course_code;
    if (entry.semester_number <= effectiveSemester) continue;
    if (isNonCoursePlaceholder(code)) continue;
    if (seenCodes.has(code) || passedCourseSet.has(code)) continue;
    if (!isOfferedForStudentProgram(code) || !checkPrereqs(code)) continue;

    addCourse(flexibleCourses, code, 'FUTURE_CORE', entry.semester_number, { credits: entry.credits });
}

for (const options of Object.values(electiveOptions)) {
    for (const option of options) flexibleCourses.push(option);
}

// P6: Fallback only when no deterministic pool was found.
if (mandatoryCourses.length === 0 && flexibleCourses.length === 0) {
    for (const [code, info] of Object.entries(offeredByCode)) {
        if (seenCodes.has(code) || passedCourseSet.has(code)) continue;
        if (!info.programs.has(studentProgram)) continue;
        if (!checkPrereqs(code)) continue;

        addCourse(flexibleCourses, code, 'FALLBACK_REMAINING', studyPlanMap[code] || null, {
            credits: creditsFor(code, info.credits),
        });
    }
}

return [{
    json: {
        student_id: studentRow.student_id,
        student_name: studentRow.name,
        academic_program: studentProgram,
        cumulative_gpa: gpa,
        career_goal: careerGoal,
        current_semester: effectiveSemester,
        semester_source: requestedSemester ? 'user_input' : 'inferred',
        mandatory_courses: mandatoryCourses,
        flexible_courses: flexibleCourses,
        elective_options: electiveOptions,
        failed_courses: failedCourses,
        max_allowed_credits: maxCredits,
        mandatory_credits: mandatoryCredits,
        remaining_credit_budget: remainingBudget,
        passed_courses_count: passedCourses.length,
        total_credits_passed: toNumber(studentRow.total_credits_passed, 0),
        legal_courses: [...mandatoryCourses, ...flexibleCourses],
        university_req_courses: [],
        cross_program_courses: [],
        _debug: {
            studyPlanEntries: studyPlanEntries.length,
            electiveGroupEntries: Object.keys(electiveGroups).length,
            offeredCourseEntries: Object.keys(offeredByCode).length,
            skipped_failed_retakes: skippedFailedRetakes,
        },
    },
}];

