const llmOutput = $('Fusion Judge').first().json.output;
const offeredCourses = $('Get Offered Courses').all().map(i => i.json);
const realNames = {};
for (const row of offeredCourses) { if (row.course_code && row.course_name) realNames[row.course_code] = row.course_name; }
if (llmOutput && llmOutput.recommended_schedule && llmOutput.recommended_schedule.courses) {
    for (const course of llmOutput.recommended_schedule.courses) { if (realNames[course.course_code]) course.course_name = realNames[course.course_code]; }
}
return [{ json: { output: llmOutput } }];

// Schedule Mapper + Conflict Detection (v2 — Smart Section Selection)
// Maps recommended course codes to their Day/Period/Room from generated_schedule
// Picks the BEST section per component (avoids conflicts when possible)
// Detects time conflicts in the student's personal timetable

const schedule = $('Fix Course Names').first().json.output.recommended_schedule;
const allScheduleRows = $('Get Offered Courses').all().map(i => i.json);
const preFilter = $('Hard Logic Pre-Filter').first().json;
const studentProgram = preFilter.academic_program;

if (!schedule || !schedule.courses) {
    return [{ json: { error: true, error_message: 'AI returned invalid schedule structure' } }];
}

const mappedCourses = [];
const conflicts = [];
const occupiedSlots = {};

for (const course of schedule.courses) {
    let slots = allScheduleRows.filter(s => s.course_code === course.course_code);

    if (slots.length === 0) {
        mappedCourses.push({
            ...course,
            slots: [],
            mapping_status: 'NOT_SCHEDULED'
        });
        continue;
    }

    // Group all available slots by component (LEC, TUT, LAB)
    const componentGroups = {};
    for (const slot of slots) {
        if (!componentGroups[slot.component]) componentGroups[slot.component] = [];
        componentGroups[slot.component].push(slot);
    }

    // Smart Section Selection: pick the section that avoids conflicts
    const selectedSlots = [];
    for (const [component, componentSlots] of Object.entries(componentGroups)) {
        // Prefer own-program sections, fall back to any program
        const ownProgSlots = componentSlots.filter(s => s.program_code === studentProgram);
        const candidates = ownProgSlots.length > 0 ? ownProgSlots : componentSlots;

        // Try to find a section that doesn't conflict with occupied slots
        let picked = null;
        for (const slot of candidates) {
            const slotKey = `${slot.day}-${slot.period}`;
            if (!occupiedSlots[slotKey]) {
                picked = slot;
                break;
            }
        }
        // Fallback: all sections conflict, pick first (conflict will be reported)
        if (!picked) picked = candidates[0];
        selectedSlots.push(picked);
    }

    const courseSlots = [];
    for (const slot of selectedSlots) {
        const slotKey = `${slot.day}-${slot.period}`;

        if (occupiedSlots[slotKey]) {
            conflicts.push({
                course_a: occupiedSlots[slotKey],
                course_b: course.course_code,
                day: slot.day,
                period: slot.period,
                conflict_type: 'TIME_OVERLAP'
            });
        } else {
            occupiedSlots[slotKey] = course.course_code;
        }

        courseSlots.push({
            component: slot.component,
            day: slot.day,
            period: slot.period,
            room: slot.room_id,
            section: slot.section
        });
    }

    mappedCourses.push({
        ...course,
        slots: courseSlots,
        mapping_status: 'MAPPED'
    });
}

const fullResponse = {
    student_id: preFilter.student_id,
    student_name: preFilter.student_name,
    academic_program: preFilter.academic_program,
    cumulative_gpa: preFilter.cumulative_gpa,
    career_goal: preFilter.career_goal,
    recommended_schedule: {
        total_credits: schedule.total_credits,
        courses: mappedCourses
    },
    conflicts: conflicts,
    has_conflicts: conflicts.length > 0
};

return [{ json: fullResponse }];

const data = $input.first().json;
if (data.error) { return [{ json: { telegram_message_text: `❌ ${data.error_message}` } }]; }
const schedule = data.recommended_schedule;
if (!schedule || !schedule.courses) { return [{ json: { telegram_message_text: '⚠️ The AI returned an invalid response. Please try again.' } }]; }
const crossProgramCodes = new Set();
try { const pf = $('Hard Logic Pre-Filter').first().json; if (pf.cross_program_courses) pf.cross_program_courses.forEach(c => crossProgramCodes.add(c.course_code)); } catch(e) {}
let md = `🎓 **Your Custom AI Schedule**\n`;
md += `👤 *${data.student_name}*\n`;
md += `📊 GPA: ${data.cumulative_gpa} | Courses: ${schedule.courses.length}\n\n`;
schedule.courses.forEach((c, i) => {
    const isCross = crossProgramCodes.has(c.course_code);
    const isUR = c.is_university_req;
    md += `${i+1}. ${isUR ? '🌐' : isCross ? '🔄' : '📚'} **${c.course_code}** — ${c.course_name || 'N/A'}\n`;
    if (isUR) md += `   📅 *Online — Thursday (schedule TBD)*\n`;
    if (isCross) md += `   ⚠️ *Cross-program course*\n`;
